import React, { useContext, useState } from 'react';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';
import {
  Drawer,
  AppBar,
  Toolbar,
  Typography,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Button,
  Box,
  Collapse,
} from '@mui/material';
import DashboardIcon from '@mui/icons-material/Dashboard';
import PointOfSaleIcon from '@mui/icons-material/PointOfSale';
import LogoutIcon from '@mui/icons-material/Logout';
import ExpandLess from '@mui/icons-material/ExpandLess';
import ExpandMore from '@mui/icons-material/ExpandMore';
import FiberManualRecordIcon from '@mui/icons-material/FiberManualRecord'; // Dot icon sub-menu er jonno
import { AuthContext } from '../context/AuthContext';

const drawerWidth = 240;

export default function AdminLayout() {
  const { logout, user } = useContext(AuthContext);
  const navigate = useNavigate();
  const location = useLocation();

  // State for sub-menus
  const [openHQ, setOpenHQ] = useState(true);
  const [openPOS, setOpenPOS] = useState(true);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const handleHQClick = () => setOpenHQ(!openHQ);
  const handlePOSClick = () => setOpenPOS(!openPOS);

  return (
    <Box sx={{ display: 'flex' }} className="bg-gray-50 min-h-screen">
      <AppBar
        position="fixed"
        sx={{ zIndex: (theme) => theme.zIndex.drawer + 1 }}
      >
        <Toolbar className="justify-between">
          <Typography variant="h6" noWrap component="div">
            Central POS System
          </Typography>
          <div className="flex items-center gap-4">
            <Typography variant="body2">Hello, {user?.name}</Typography>
            <Button
              color="inherit"
              onClick={handleLogout}
              startIcon={<LogoutIcon />}
            >
              Logout
            </Button>
          </div>
        </Toolbar>
      </AppBar>

      <Drawer
        variant="permanent"
        sx={{
          width: drawerWidth,
          flexShrink: 0,
          [`& .MuiDrawer-paper`]: {
            width: drawerWidth,
            boxSizing: 'border-box',
          },
        }}
      >
        <Toolbar />
        <Box sx={{ overflow: 'auto' }}>
          <List>
            {/* HQ Dashboard Section */}
            <ListItem button onClick={handleHQClick}>
              <ListItemIcon>
                <DashboardIcon />
              </ListItemIcon>
              <ListItemText primary="HQ Dashboard" />
              {openHQ ? <ExpandLess /> : <ExpandMore />}
            </ListItem>

            <Collapse in={openHQ} timeout="auto" unmountOnExit>
              <List component="div" disablePadding>
                <ListItem
                  button
                  sx={{ pl: 4 }}
                  onClick={() => navigate('/master-menu')}
                  selected={location.pathname === '/master-menu'}
                >
                  <ListItemIcon>
                    <FiberManualRecordIcon sx={{ fontSize: 10 }} />
                  </ListItemIcon>
                  <ListItemText primary="Master Menu" />
                </ListItem>
                <ListItem
                  button
                  sx={{ pl: 4 }}
                  onClick={() => navigate('/outlet-products')}
                  selected={location.pathname === '/outlet-products'}
                >
                  <ListItemIcon>
                    {/* <FiberManualRecordIcon sx={{ fontSize: 10 }} /> */}
                  </ListItemIcon>
                  <ListItemText primary="Outlet Products" />
                </ListItem>
              </List>
            </Collapse>

            {/* POS Terminal Section */}
            <ListItem button onClick={handlePOSClick}>
              <ListItemIcon>
                <PointOfSaleIcon />
              </ListItemIcon>
              <ListItemText primary="POS Terminal" />
              {openPOS ? <ExpandLess /> : <ExpandMore />}
            </ListItem>

            <Collapse in={openPOS} timeout="auto" unmountOnExit>
              <List component="div" disablePadding>
                <ListItem
                  button
                  sx={{ pl: 4 }}
                  onClick={() => navigate('/pos-master')}
                  selected={location.pathname === '/pos-master'}
                >
                  <ListItemIcon>
                    {/* <FiberManualRecordIcon sx={{ fontSize: 10 }} /> */}
                  </ListItemIcon>
                  <ListItemText primary="Master Menu" />
                </ListItem>
                <ListItem
                  button
                  sx={{ pl: 4 }}
                  onClick={() => navigate('/pos-products')}
                  selected={location.pathname === '/pos-products'}
                >
                  <ListItemIcon>
                    <FiberManualRecordIcon sx={{ fontSize: 10 }} />
                  </ListItemIcon>
                  <ListItemText primary="Outlet Products" />
                </ListItem>
              </List>
            </Collapse>
          </List>
        </Box>
      </Drawer>

      <Box component="main" sx={{ flexGrow: 1, p: 3 }}>
        <Toolbar />
        <Outlet />
      </Box>
    </Box>
  );
}
